<span class="line"><span style="color:#F92672;">        if</span><span style="color:#F8F8F2;"> event.type </span><span style="color:#F92672;">==</span><span style="color:#F8F8F2;"> pygame.</span><span style="color:#AE81FF;">KEYDOWN</span><span style="color:#F8F8F2;">:</span></span>
